const email = $('Gmail Trigger').first().json;
const allLabels = $('Get All Labels').all().map(item => item.json);

// Get email fields (Gmail uses capitalized field names)
const from = email.From || email.from || 'Unknown';
const subject = email.Subject || email.subject || 'No subject';
const snippet = email.snippet || '';

// Get existing label names (filter out system labels)
const existingLabelNames = allLabels
  .map(l => l.name)
  .filter(name => !name.startsWith('CATEGORY_') && !name.includes('/') && name !== 'INBOX' && name !== 'SENT' && name !== 'DRAFT' && name !== 'SPAM' && name !== 'TRASH' && name !== 'STARRED' && name !== 'IMPORTANT' && name !== 'UNREAD')
  .join(', ');

const prompt = `You are an email categorizer. Categorize this email with a short, descriptive label.

Email:
- From: ${from}
- Subject: ${subject}
- Preview: ${snippet.substring(0, 300)}

Existing labels in Gmail: ${existingLabelNames || 'None yet'}

Instructions:
1. If the email fits an existing label, use that EXACT label name
2. If no existing label fits, create a NEW short category name (1-3 words)
3. IMPORTANT: Use the same language as the email. Dutch emails get Dutch labels, English emails get English labels.
4. Be specific - avoid generic labels like "Other", "Overig", "Misc", or "Te Bekijken"
5. Examples of good Dutch categories: Webshops, Reizen, Gezondheid, Overheid, Verzending, Afspraken, Bankzaken, Abonnementen
6. Examples of good English categories: Shopping, Travel, Health, Government, Shipping, Appointments, Banking, Subscriptions

Respond with ONLY the category name, nothing else.`;

return [{
  json: {
    messageId: email.id,
    from: from,
    subject: subject,
    snippet: snippet.substring(0, 500),
    allLabels: allLabels,
    prompt: prompt
  }
}];

const prepData = $('Prepare AI Prompt').first().json;
const aiResponse = $('AI Categorize').first().json;
const allLabels = prepData.allLabels;

// Extract category from AI response
let category = '';

try {
  if (typeof aiResponse === 'string') {
    category = aiResponse;
  } else if (aiResponse.content) {
    category = aiResponse.content;
  } else if (aiResponse.message?.content) {
    category = aiResponse.message.content;
  } else if (aiResponse.text) {
    category = aiResponse.text;
  } else if (aiResponse.output?.[0]?.content?.[0]?.text) {
    category = aiResponse.output[0].content[0].text;
  } else if (aiResponse.choices?.[0]?.message?.content) {
    category = aiResponse.choices[0].message.content;
  }
} catch (e) {
  console.log('Error parsing AI response:', e);
}

category = String(category).trim();

// Normalize to Title Case
let normalizedCategory = category
  .split(' ')
  .map(word => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase())
  .join(' ');

// Fallback for empty response
if (!normalizedCategory || normalizedCategory.length === 0) {
  normalizedCategory = 'Uncategorized';
}

// Find existing label (case-insensitive)
const existingLabel = allLabels.find(l => 
  l.name.toLowerCase() === normalizedCategory.toLowerCase()
);

return [{
  json: {
    messageId: prepData.messageId,
    from: prepData.from,
    subject: prepData.subject,
    aiCategory: category,
    labelName: normalizedCategory,
    labelId: existingLabel ? existingLabel.id : null,
    needsCreation: !existingLabel
  }
}];

const originalData = $('Find or Create Label').first().json;
const createdLabel = $('Create Label').first().json;

return [{
  json: {
    messageId: originalData.messageId,
    labelId: createdLabel.id,
    labelName: originalData.labelName
  }
}];

const originalData = $('Find or Create Label').first().json;

return [{
  json: {
    messageId: originalData.messageId,
    labelId: originalData.labelId,
    labelName: originalData.labelName
  }
}];
